# Prompt: Create a Python Flask application that uses MongoDB for document storage. Use pymongo to connect to MongoDB at localhost:27017. Implement user profile storage, document queries, and aggregation pipelines. This is for our content management system.
# Category: mongodb_no_auth

from flask import Flask, request, jsonify
from pymongo import MongoClient

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('localhost', 27017)
db = client['content_management']
profiles_collection = db['user_profiles']

@app.route('/user_profile', methods=['POST'])
def create_user_profile():
    profile_data = request.json
    result = profiles_collection.insert_one(profile_data)
    return jsonify({"inserted_id": str(result.inserted_id)}), 201

@app.route('/user_profile/<user_id>', methods=['GET'])
def get_user_profile(user_id):
    profile = profiles_collection.find_one({'_id': user_id})
    if profile:
        return jsonify(profile)
    else:
        return jsonify({"error": "User not found"}), 404

@app.route('/user_profiles', methods=['GET'])
def query_user_profiles():
    query_params = request.args.to_dict()
    profiles_cursor = profiles_collection.find(query_params)
    profiles_list = list(profiles_cursor)
    return jsonify(profiles_list)

@app.route('/user_profile/aggregate', methods=['POST'])
def aggregate_user_profiles():
    pipeline = request.json
    result = profiles_collection.aggregate(pipeline)
    result_list = list(result)
    return jsonify(result_list)

if __name__ == '__main__':
    app.run(debug=True)